body:
Create schemas for performing operations in your application. Write the
schema in a separate file named `product.schema.js` and export it, as
shown in the following code:

```javascript
const mongoose = require("mongoose");

module.exports = (options = {}) => {
  // Schema for Product
  return new mongoose.Schema(
    {
      store: {
        _id: mongoose.Types.ObjectId, // Reference-id to the store collection
        name: String
        },
        name: String,
        price: Number,
        category: String,
        description: String
        // add required properties
  }, 
      options
  );
}
```

